import { useState } from 'react';
import Bebidas from '../bebidas/bebidas';
import Burguers from '../burguers/burguers';
import Combos from '../combos/combos';
import './productos.css';


function Productos() {
    const [carrito, setCarrito] = useState([])



    function vaciarCarrito(){
        setCarrito = []
    }

    return (
        <div className='cont-prod-mayor'>
            <h2>PRODUCTOS</h2>
            <Combos carrito={carrito} setCarrito={setCarrito}  />
            <Burguers carrito={carrito} setCarrito={setCarrito}  />
            <Bebidas carrito={carrito} setCarrito={setCarrito}  />
        </div>
    )
}

export default Productos;
